# Install/load required packages
if(!require(httr)) install.packages("httr")
if(!require(rvest)) install.packages("rvest")
if(!require(xml2)) install.packages("xml2")
if(!require(stringr)) install.packages("stringr")
if(!require(dplyr)) install.packages("dplyr")
library(purrr)


#' @title Discover Tennis Warehouse Racquet Reviews
#' @description Attempts to find all racquet review pages from the sitemap and the main
#'   reviews listing page, returning a tibble with (model, brand, code, link).
discover_racquet_reviews <- function() {
  # -------------------------------------------------------------------------
  # 1) Discover links from the sitemap
  # -------------------------------------------------------------------------
  sitemap_url  <- "https://www.tennis-warehouse.com/sitemap.xml"
  sitemap_resp <- GET(sitemap_url)
  sitemap_links <- character(0)

  if (status_code(sitemap_resp) == 200) {
    sitemap_xml <- read_xml(content(sitemap_resp, as = "text", encoding = "UTF-8"))
    all_urls <- xml_find_all(sitemap_xml, ".//loc") %>% xml_text()

    # Filter for URLs that contain /learning_center/racquet_reviews/
    sitemap_links <- all_urls[str_detect(all_urls, "/learning_center/racquet_reviews/")]
  } else {
    message("Sitemap not found or inaccessible.")
  }

  # We'll create a tibble for these. We don't have brand/model from the sitemap,
  # so set them to NA. We can parse the 'code' from the URL, but keep in mind
  # the substring might not match the gtm_impression_code from the main page exactly.
  df_sitemap <- tibble(
    model = NA_character_,
    brand = NA_character_,
    # Example code extraction (if you want a code column):
    code  = str_extract(sitemap_links, "(?<=racquet_reviews/)[^/]+(?=.html)"),
    link  = sitemap_links
  )

  # -------------------------------------------------------------------------
  # 2) Scrape the main "reviewedracquets.html" page for brand, model, code
  # -------------------------------------------------------------------------
  main_page_url <- "https://www.tennis-warehouse.com/reviewedracquets.html"
  main_page <- tryCatch(read_html(main_page_url), error = function(e) NULL)

  df_main <- tibble(model = character(0), brand = character(0), code = character(0), link = character(0))

  if (!is.null(main_page)) {
    # Extract brand, model, code from data-gtm_impression attributes
    impression_nodes <- main_page %>% html_nodes("div.cattable-wrap-cell.gtm_impression")

    brands <- impression_nodes %>% html_attr("data-gtm_impression_brand")
    models <- impression_nodes %>% html_attr("data-gtm_impression_name")
    codes  <- impression_nodes %>% html_attr("data-gtm_impression_code")

    # Extract actual links from the relevant container
    link_nodes <- main_page %>%
      html_nodes("div.cattable-wrap-cell-imgwrap.is-racquet") %>%
      html_nodes("a") %>%
      html_attr("href")

    links <- paste0("https://www.tennis-warehouse.com", link_nodes)

    # Combine into a tibble
    df_main <- tibble(
      model = models,
      brand = brands,
      code  = codes,
      link  = links
    )
  } else {
    message("Failed to scrape main reviews page.")
  }

  # -------------------------------------------------------------------------
  # 3) Combine both sets of results, remove duplicates, clean the 'link' column
  # -------------------------------------------------------------------------
  df_out <- bind_rows(df_sitemap, df_main) %>%
    mutate(
      # Remove any carriage returns/newlines from link,
      # then trim any leading/trailing whitespace.
      link = link %>%
        str_replace_all("[\r\n]", "") %>%
        str_trim()
    ) %>%
    distinct(link, .keep_all = TRUE)

  return(df_out)
}


get_clean_html <- function(url) {
  # Minimal placeholder for your existing logic...
  tryCatch(
    xml2::read_html(url),
    error = function(e) {
      message("Error reading URL: ", url, " => ", e$message)
      return(NULL)
    }
  )
}


get_clean_html <- function(url) {
  # Minimal placeholder logic. Could handle user agents, retries, etc.
  tryCatch(
    { xml2::read_html(url) },
    error = function(e) {
      message("Error reading URL: ", url)
      return(NULL)
    }
  )
}

gather_intel_on_review_page <- function(url) {
  doc <- get_clean_html(url)
  if (is.null(doc)) {
    return(tibble(
      link = url,
      ok   = FALSE,
      # You can track as many features as you want, here is just an example set:
      has_div_scores           = NA_integer_,
      has_div_review_scores    = NA_integer_,
      has_div_scores_table     = NA_integer_,
      has_div_score_box        = NA_integer_,
      has_old_specs_table      = NA_integer_,
      has_racquet_rate_table   = NA_integer_,
      has_breakdown_summary_id = NA_integer_,
      has_playtester_sections  = NA_integer_,
      has_new_breakdown_table  = NA_integer_,
      has_new_twu_labdata      = NA_integer_,
      has_new_tech_specs       = NA_integer_
    ))
  }

  # ============ OLD-STYLE checks ============
  ds        <- doc %>% html_nodes("div.scores")
  ds2       <- doc %>% html_nodes("div.review_scores")
  ds_tab    <- doc %>% html_nodes("div.scores table")
  ds_sbox   <- doc %>% html_nodes("div.score_box")
  old_specs <- doc %>% html_nodes("table.racquet_specs_table")
  rrate     <- doc %>% html_nodes("table.racquet_rate_table")
  breakdown <- doc %>% html_nodes("#breakdown_summary")
  # or doc %>% html_nodes("#breakdown_summary table")

  # ============ NEW-STYLE checks ============
  # E.g. "div#table.table-responsive.review-table table" might be the new breakdown
  new_breakdown <- doc %>% html_nodes("div#table.table-responsive.review-table table")
  # TWU lab data in #table_data
  new_lab_data  <- doc %>% html_nodes("#table_data table")
  # Tech specs in #tech_specs or #US / #EU
  new_techspecs <- doc %>% html_nodes("#tech_specs table")

  # The .review-playtesters_section blocks for the new style:
  ptesters <- doc %>% html_nodes(".review-playtesters_section")

  tibble(
    link       = url,
    ok         = TRUE,
    # OLD
    has_div_scores        = length(ds),
    has_div_review_scores = length(ds2),
    has_div_scores_table  = length(ds_tab),
    has_div_score_box     = length(ds_sbox),
    has_old_specs_table   = length(old_specs),
    has_racquet_rate_table= length(rrate),
    has_breakdown_summary_id = length(breakdown),

    # NEW
    has_playtester_sections = length(ptesters),
    has_new_breakdown_table = length(new_breakdown),
    has_new_twu_labdata     = length(new_lab_data),
    has_new_tech_specs      = length(new_techspecs)
  )
}


# Optional wrapper if you want to do many links at once:
gather_intel_on_many_pages <- function(urls) {
  # lapply or purrr::map over the set of links
  result_list <- lapply(urls, gather_intel_on_review_page)
  bind_rows(result_list)
}


