library(rvest)
library(dplyr)
library(stringr)
library(purrr)

parse_new_style <- function(doc) {
  # We'll store both the staff "breakdown summary" plus each individual's breakdown
  out_list <- list()

  # STEP 1: Gather all "table.table-borderless" nodes from the main review container.
  #         We do want to skip "Tech Specs" tables and "Lab Data" tables.
  candidate_tables <- doc %>%
    html_node("div.review-body_container") %>% # or "div.review-container"
    html_nodes("table.table.table-borderless")

  if (length(candidate_tables) == 0) {
    return(tibble())
  }

  # We'll parse each table and see if it looks like a "score table"
  # vs. a "tech specs" vs. a "lab data" or "playtester" table.
  out_all <- map_dfr(candidate_tables, function(tbl) {

    # Quick text check to see if this table is obviously Tech Specs or Lab Data
    # If it has "Length" / "Head Size" / "Flex Rating" in the first row, skip.
    all_text <- tbl %>% html_text()
    if (grepl("(Length|Flex Rating|Swing Weight|Head Size)", all_text, ignore.case=TRUE)) {
      # we skip "tech specs" or "lab data" tables
      return(tibble())
    }

    # If not a Tech Specs table, we proceed to see if it's the staff or a player table.
    rows <- tbl %>% html_nodes("tr")
    if (length(rows) == 0) return(tibble())

    # The first row might say "Groundstrokes" or "Michelle's Breakdown" or "Chris' Breakdown"...
    # or it might have category/score pairs directly.
    # We'll see if the FIRST row has a single <td colspan="2"> with text like "Chris's Breakdown".
    # If so, we parse from row 2 onward for the category/score pairs.

    # We'll read the entire text of the first <tr>:
    first_tr_text <- rows[[1]] %>% html_text(trim=TRUE)

    # If that first line says something like "Michelle's Breakdown" or "Troy's Breakdown", etc.
    # we can parse out the name.
    # We'll do a simple pattern:
    # e.g. "Michelle's Breakdown" => "Michelle"
    # If it does NOT match that pattern, maybe it's the "Breakdown Summary" (the staff row).
    # We'll guess "TW Staff" for that scenario.

    # We also might see "Groundstrokes  8.3" right away if the first row is already a category row.
    # So let’s see if the first row is a single cell with "someone's breakdown" or if it’s 2 cells.

    tds_first_tr <- rows[[1]] %>% html_nodes("td")
    if (length(tds_first_tr) == 1) {
      # Probably something like "Michelle's Breakdown" in one big colspan.
      # We'll parse out the name:
      # e.g. "Michelle's Breakdown"
      # We'll strip off "'s Breakdown"
      possible_name <- first_tr_text
      # remove trailing "’s Breakdown" or "’ Scores"
      possible_name <- str_remove(possible_name, "'?s Breakdown")
      possible_name <- str_remove(possible_name, "'?s Scores")
      # handle any leftover
      possible_name <- str_squish(possible_name)

      # Now parse subsequent rows as category/score pairs
      if (length(rows) > 1) {
        # the real data starts at row 2
        row_data <- rows[-1]
      } else {
        return(tibble())
      }
    } else {
      # This might be the staff table, or it might simply start with a category row
      # We'll call the player "TW Staff" for that scenario
      # (or we can set "unknown" until we see if there's a "Final Verdict" row)
      possible_name <- "TW Staff"
      row_data <- rows
    }

    # Now parse each row in row_data
    # Usually each row has 2 columns: category, score
    # final verdict row might say "Final Verdict" and "8.3"
    data_rows <- map_dfr(row_data, function(rr) {
      tds <- rr %>% html_nodes("td")
      if (length(tds) == 2) {
        cat_text   <- html_text(tds[[1]], trim=TRUE)
        score_text <- html_text(tds[[2]], trim=TRUE)
        tibble(
          player   = possible_name,
          category = cat_text,
          score    = score_text
        )
      } else {
        tibble()
      }
    })

    data_rows
  })

  # That should combine staff + each individual's table (unless we found "tech specs" or "lab data").
  out_all
}



# parse main "TW Staff" summary table from old style (div.scores)
parse_main_scores_oldstyle <- function(doc) {
  out <- tibble()
  main_tbl <- doc %>% html_node("div.scores table")
  if (!is.null(main_tbl)) {
    rows <- main_tbl %>% html_nodes("tr")
    out_list <- lapply(rows, function(rr) {
      tds <- rr %>% html_nodes("th, td") %>% html_text(trim=TRUE)
      if (length(tds)==2) {
        tibble(player="TW Staff", category=tds[1], score=tds[2])
      } else {
        NULL
      }
    })
    out <- bind_rows(out_list)
  }
  out
}

# parse old style "table.playscore" for individual testers
parse_individual_scores_oldstyle <- function(doc) {
  out <- tibble()
  playscore_tables <- doc %>% html_nodes("table.playscore")
  if (length(playscore_tables) == 0) return(out)

  all_data <- lapply(playscore_tables, function(tbl) {
    # get player name from top row
    first_th <- tbl %>% html_node("tr th")
    if (is.null(first_th)) return(NULL)
    heading_text <- html_text(first_th, trim=TRUE)
    # e.g., "Chris' Scores" -> "Chris"
    # you can just store the raw heading_text, or strip out " Scores"
    heading_text <- sub(" Scores$", "", heading_text)

    # parse subsequent rows
    rows_ <- tbl %>% html_nodes("tr")
    # typically first row is the heading row -> skip
    if (length(rows_) > 1) rows_ <- rows_[-1]
    out_each <- lapply(rows_, function(rr) {
      tds <- rr %>% html_nodes("td") %>% html_text(trim=TRUE)
      # tds might be c("Power","8.4","Serves","8.7")
      # parse them in pairs
      small_list <- list()
      if (length(tds) >= 2) {
        small_list[[1]] <- tibble(
          player=heading_text,
          category=tds[1],
          score=tds[2]
        )
      }
      if (length(tds) >= 4) {
        small_list[[2]] <- tibble(
          player=heading_text,
          category=tds[3],
          score=tds[4]
        )
      }
      bind_rows(small_list)
    })
    bind_rows(out_each)
  })

  out <- bind_rows(all_data)
  out
}

parse_racquet_specs <- function(doc) {
  length_        <- NA_character_
  head_size_     <- NA_character_
  weight_        <- NA_character_
  balance_       <- NA_character_
  construction_  <- NA_character_
  material_      <- NA_character_
  string_pattern <- NA_character_

  # ---------------------------
  # 1) Attempt OLD-STYLE table
  # ---------------------------
  specs_tbl <- doc %>% rvest::html_node("table.racquet_specs_table")
  if (!is.null(specs_tbl)) {
    rows <- specs_tbl %>% rvest::html_nodes("tr")
    for (rr in rows) {
      cols <- rr %>% rvest::html_nodes("th, td") %>% rvest::html_text(trim=TRUE)
      if (length(cols) >= 2) {
        label <- cols[1]
        val   <- cols[2]
        if (grepl("^Length", label, ignore.case=TRUE))            length_        <- val
        if (grepl("^Head Size", label, ignore.case=TRUE))         head_size_     <- val
        if (grepl("^Weight", label, ignore.case=TRUE))            weight_        <- val
        if (grepl("^Balance", label, ignore.case=TRUE))           balance_       <- val
        if (grepl("^Construction", label, ignore.case=TRUE))      construction_  <- val
        if (grepl("String Pattern", label, ignore.case=TRUE))     string_pattern <- val
        if (grepl("Composition|Material", label, ignore.case=TRUE)) material_     <- val
      }
    }
  }

  # -----------------------------
  # 2) Attempt “New Style” specs
  #    if we still have all NA
  # -----------------------------
  # Some pages have class="review-techspecs",
  # others have class="review-techspec" (singular).
  # Also note #US is often in a sibling or child node.
  if (all(is.na(c(length_, head_size_, weight_, balance_, construction_, material_, string_pattern)))) {
    new_style_tbl <- doc %>%
      # This selector says: find EITHER div.review-techspec OR div.review-techspecs
      html_node("div.review-techspec, div.review-techspecs") %>%
      # Then within that, look for #US table.table-borderless
      html_node("#US table.table-borderless")

    if (!is.null(new_style_tbl)) {
      rows <- new_style_tbl %>% rvest::html_nodes("tr")
      for (rr in rows) {
        cols <- rr %>% rvest::html_nodes("td") %>% rvest::html_text(trim=TRUE)
        if (length(cols) >= 2) {
          label <- cols[1]
          val   <- cols[2]
          if (grepl("^Length", label, ignore.case=TRUE))            length_        <- val
          if (grepl("^Head Size", label, ignore.case=TRUE))         head_size_     <- val
          if (grepl("^Weight", label, ignore.case=TRUE))            weight_        <- val
          if (grepl("^Balance", label, ignore.case=TRUE))           balance_       <- val
          if (grepl("^Construction", label, ignore.case=TRUE))      construction_  <- val
          if (grepl("String Pattern", label, ignore.case=TRUE))     string_pattern <- val
          if (grepl("Composition|Material", label, ignore.case=TRUE)) material_     <- val
        }
      }
    }
  }

  list(
    length        = length_,
    head_size     = head_size_,
    weight        = weight_,
    balance       = balance_,
    construction  = construction_,
    material      = material_,
    string_pattern= string_pattern
  )
}

parse_racquet_rdc <- function(doc) {
  flex <- NA_real_
  swingweight <- NA_real_

  # ---------------------------
  # 1) Attempt OLD-STYLE <table.racquet_rate_table>
  # ---------------------------
  rdc_tbl <- doc %>% rvest::html_node("table.racquet_rate_table")
  if (!is.null(rdc_tbl)) {
    rows <- rdc_tbl %>% rvest::html_nodes("tr")
    for (rr in rows) {
      tds <- rr %>% rvest::html_nodes("th, td") %>% rvest::html_text(trim=TRUE)
      # e.g.: c("Flex Rating","65","Range: 0-100")
      # or   c("Swing Weight","322","Range: 200-400")
      if (length(tds) >= 2) {
        if (grepl("Flex Rating", tds[1], ignore.case=TRUE)) {
          flex <- suppressWarnings(as.numeric(tds[2]))
        }
        if (grepl("Swing Weight", tds[1], ignore.case=TRUE)) {
          swingweight <- suppressWarnings(as.numeric(tds[2]))
        }
      }
    }
  }

  # ---------------------------
  # 2) NEW-STYLE Variations (Partial Overwrite)
  # ---------------------------
  # If either flex or swingweight is still NA, check new layouts
  if (is.na(flex) || is.na(swingweight)) {
    # Try multiple selectors for new-style tables
    selectors <- c("table#table_data", ".review-table_data table", ".table-responsive.review-table table")
    new_lab_tbl <- NULL
    for (sel in selectors) {
      new_lab_tbl <- doc %>% rvest::html_node(sel)
      if (!is.na(new_lab_tbl)) break
    }

    if (!is.na(new_lab_tbl)) {
      rows <- new_lab_tbl %>% rvest::html_nodes("tr")
      for (rr in rows) {
        tds <- rr %>% rvest::html_nodes("td") %>% rvest::html_text(trim=TRUE)
        # e.g. c("Flex Rating", "66", "MEDIUM")
        #      c("Swing Weight", "314", "LOW")
        if (length(tds) >= 2) {
          if (grepl("Flex Rating", tds[1], ignore.case=TRUE)) {
            # only overwrite if flex is NA
            if (is.na(flex)) {
              flex <- suppressWarnings(as.numeric(tds[2]))
            }
          }
          if (grepl("Swing Weight", tds[1], ignore.case=TRUE)) {
            # only overwrite if swingweight is NA
            if (is.na(swingweight)) {
              swingweight <- suppressWarnings(as.numeric(tds[2]))
            }
          }
        }
      }
    }
  }

  if (is.na(flex)) {
    browser()
  }

  list(flex = flex, swingweight = swingweight)
}

parse_racquet_review <- function(intelligence_row, model, brand, code) {
  link <- intelligence_row[["link"]]
  message("===== Parsing racquet review for link: ", link)

  doc <- get_clean_html(link)
  if (is.null(doc)) {
    warning("Failed to retrieve HTML for link: ", link)
    return(tibble())
  }

  # 1) Try old-style parse for scores
  oldstyle_main <- parse_main_scores_oldstyle(doc)
  oldstyle_individual <- parse_individual_scores_oldstyle(doc)

  # 2) If both old style calls returned empty, check new style
  all_scores <- bind_rows(oldstyle_main, oldstyle_individual)
  if (nrow(all_scores) == 0) {
    newstyle_scores <- parse_new_style(doc)
    all_scores <- newstyle_scores
  }

  if (nrow(all_scores) == 0) {
    message("No scores found. Returning empty tibble.")
    return(tibble())
  }

  # 3) Parse specs & RDC
  specs_list <- parse_racquet_specs(doc)
  rdc_list   <- parse_racquet_rdc(doc)

  # 4) Return combined
  out <- all_scores %>%
    mutate(
      model  = model,
      code   = code,
      brand  = brand,
      flex         = rdc_list$flex,
      swingweight  = rdc_list$swingweight,
      length       = specs_list$length,
      head_size    = specs_list$head_size,
      weight       = specs_list$weight,
      balance      = specs_list$balance,
      construction = specs_list$construction,
      material     = specs_list$material,
      string_pattern = specs_list$string_pattern
    ) %>%
    select(player, category, score,
           model, code, brand,
           flex, swingweight, length, head_size, weight,
           balance, construction, material, string_pattern)

  message("===== Done parsing link: ", link,
          " --> found ", nrow(out), " total scores.")
  return(out)
}

post_process_review <- function(df) {
  library(dplyr)
  library(stringr)

  df <- df %>%
    mutate(
      #################################################################
      ## 1) Convert score to numeric on a 0–10 scale
      #################################################################
      # - Convert to numeric if possible
      # - If score > 10, assume it was out of 100 and divide by 10
      # - Otherwise leave it as-is
      score = as.numeric(score),
      score = case_when(
        is.na(score) ~ NA_real_,
        score > 10   ~ score / 10,
        TRUE         ~ score
      ),

      #################################################################
      ## 2) Parse numeric columns from strings
      #################################################################

      # ----- Weight (e.g. "11.2 oz", "10.7 oz") -----
      # We'll extract up to the first numeric part, ignoring "oz".
      # If unparseable, we get NA.
      weight_numeric = as.numeric(str_extract(weight, "[0-9\\.]+")),

      # ----- Length (e.g. "27.5 in", "27.5 inch") -----
      # We'll likewise extract the first numeric portion.
      length_numeric = as.numeric(str_extract(length, "[0-9\\.]+")),

      # ----- Head size (e.g. "100 sq in", "98", "95 in", etc.) -----
      # We look for numeric portion. If unparseable => NA.
      head_size_numeric = as.numeric(str_extract(head_size, "[0-9\\.]+")),

      # ----- Balance (inches from butt)
      # We'll parse the first floating number. If none => NA.
      balance_in = as.numeric(str_extract(balance, "[0-9\\.]+")),

      #################################################################
      ## 3) Clean up / unify string_pattern to "16x19", "16x20", etc.
      #################################################################
      # We'll do a series of replacements to unify forms like:
      #   "16 / 19", "16x19", "16 x 19", "16 Mains / 19 Crosses", etc.
      #
      # Then we keep only digits + 'x' in the final pattern. E.g. "16x19".
      # If you have patterns like "19x19" or "14x18", you can keep them,
      # or define them in the replacements below.
      #
      # We do everything in one go using "case_when" or stepwise gsub.
      # Because there are multiple forms, a small chain of gsub often is easiest.
      #################################################################
      pattern_cleaned = string_pattern %>%
        # Convert "mains" or "Mains" or "crosses" or "Crosses" => remove them
        str_replace_all("(?i)mains|crosses", "") %>%
        # Convert "x", " X ", " / ", etc. to a single "x"
        str_replace_all("(?i)[^0-9]+", "x") %>%    # anything not a digit => "x"
        # This might result in patterns like "16x19x" if there is a trailing character.
        # We'll trim trailing x if present
        str_remove_all("x$") %>%
        # If we had "16x18x19" that might be a problem, so keep only the first two groups of digits:
        # We'll do a quick fix: keep only the first 2 groups of digits separated by 'x'
        # e.g. "16x19x" => "16x19"
        # For safety, let's do a more explicit approach:
        str_extract("^\\d{1,2}x\\d{1,2}")  # e.g. "16x19" or "18x20" or "16x18"

      # You could do more advanced logic if your data has weird outliers.
      # Or you can coalesce to NA if unmatched.
    ) %>%
    # Because we may want a single combined "string density" that merges head_size and pattern
    # we can create it after the above mutate. E.g. "100in_16x19"
    mutate(
      string_density = if_else(
        !is.na(head_size_numeric) & !is.na(pattern_cleaned),
        paste0(head_size_numeric, "in_", pattern_cleaned),
        NA_character_
      )
    )

  df %>%
    mutate(
      # First parse numeric from 'balance' and store in inches
      balance_in = as.numeric(str_extract(balance, "[0-9\\.]+")),
      # Also parse numeric from 'length'. If missing, fallback to 27 inches:
      length_in  = as.numeric(str_extract(length, "[0-9\\.]+")),
      length_in  = if_else(is.na(length_in), 27, length_in),

      # Compute midpoint in inches
      midpoint_in = length_in / 2,

      # Distance from midpoint (if positive => racquet is head-light)
      balance_diff_in = midpoint_in - balance_in,

      # Convert that difference to "points" (1 point = 1/8 inch)
      # Round to nearest integer for typical labeling
      balance_pts_num = round(8 * abs(balance_diff_in)),

      # Finally, create a text label such as "4 pts HL" or "2 pts HH"
      # or "EB" if difference is near zero
      balance_pts = case_when(
        is.na(balance_in) ~ NA_character_,
        abs(balance_diff_in) < 0.05 ~ "EB",  # small threshold for even
        balance_diff_in > 0        ~ paste0(balance_pts_num, " pts HL"),
        TRUE                       ~ paste0(balance_pts_num, " pts HH")
      )
    )
}


