# all_review_data is your final data frame of racquet review info
processed_data <- post_process_review(all_review_data)


parse_review_text <- function(link) {

  doc <- tryCatch({
    read_html(link)
  }, error = function(e) {
    warning("Could not read HTML: ", e$message)
    return(NULL)
  })

  if (is.null(doc)) {
    return(list(
      summary_text = NA_character_,
      body_text = NA_character_,
      likes_text = NA_character_,
      dislikes_text = NA_character_,
      comparing_text = NA_character_,
      playtester_profiles = NA_character_
    ))
  }

  # Helper function: gather text from a set of nodes
  # and return as one text block
  node_text_block <- function(html_nodeset) {
    text_vec <- html_nodeset %>%
      html_text2() %>%            # get text (html_text2 has no trim arg)
      str_trim(side = "both")     # strip leading/trailing whitespace
    paste(text_vec, collapse = "\n\n")
  }

  # Extract summary from 'div.review_breakdown'
  summary_node <- doc %>% html_node("div.review_breakdown")
  summary_text <- if (!is.null(summary_node)) {
    # get paragraphs + list items
    node_text_block(summary_node %>% html_nodes("p, li"))
  } else NA_character_

  # Extract main body from 'div.review_body'
  body_node <- doc %>% html_node("div.review_body")
  body_text <- if (!is.null(body_node)) {
    node_text_block(body_node %>% html_nodes("p"))
  } else NA_character_

  # Extract Likes / Dislikes / Comparing from 'div.review_comments'
  likes_text     <- NA_character_
  dislikes_text  <- NA_character_
  comparing_text <- NA_character_

  comments_node <- doc %>% html_node("div.review_comments")
  if (!is.null(comments_node)) {
    comment_boxes <- comments_node %>% html_nodes("div.review_comment_box")
    for (cb in comment_boxes) {
      heading <- cb %>% html_node("h2") %>% html_text2() %>% str_trim()
      cblock_txt <- node_text_block(cb %>% html_nodes("p"))

      if (grepl("likes", heading, ignore.case = TRUE)) {
        likes_text <- cblock_txt
      } else if (grepl("dislike", heading, ignore.case = TRUE)) {
        dislikes_text <- cblock_txt
      } else if (grepl("Comparing the racquet", heading, ignore.case=TRUE)) {
        comparing_text <- cblock_txt
      }
    }
  }

  # Extract playtester profiles from 'div.playtest_profiles'
  playtest_profiles_node <- doc %>% html_node("div.playtest_profiles")
  playtester_profiles <- if (!is.null(playtest_profiles_node)) {
    node_text_block(playtest_profiles_node %>% html_nodes("p"))
  } else NA_character_

  # Return a list with all captured text
  list(
    summary_text         = summary_text,
    body_text            = body_text,
    likes_text           = likes_text,
    dislikes_text        = dislikes_text,
    comparing_text       = comparing_text,
    playtester_profiles  = playtester_profiles
  )
}

