import type { Metadata } from "next";
import { Inter } from "next/font/google";
import "./globals.css";

const inter = Inter({
  subsets: ["latin"],
  variable: "--font-inter",
});

export const metadata: Metadata = {
  title: "Tennis Racquet Explorer",
  description: "Discover the perfect tennis racquet through the intersection of feel and physics",
  keywords: "tennis, racquet, racket, specs, reviews, comparison, tennis equipment",
  authors: [{ name: "Tennis Racquet Explorer" }],
  openGraph: {
    title: "Tennis Racquet Explorer",
    description: "Discover the perfect tennis racquet through the intersection of feel and physics",
    type: "website",
    locale: "en_US",
  },
  twitter: {
    card: "summary_large_image",
    title: "Tennis Racquet Explorer",
    description: "Discover the perfect tennis racquet through the intersection of feel and physics",
  },
  viewport: "width=device-width, initial-scale=1",
  themeColor: "#228B22",
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en" className={inter.variable}>
      <body className="antialiased">
        {children}
      </body>
    </html>
  );
}

