}

function parseRDataFile(filePath: string): RawDataRow[] {
  const content = fs.readFileSync(filePath, 'utf-8');
  const lines = content.split('\n');

  if (lines.length < 2) {
    throw new Error('Invalid data file format');
  }

  // Parse header
  const header = lines[0]
    .split(' ')
    .map(col => col.replace(/"/g, '').trim())
    .filter(col => col.length > 0);

  console.log('Header columns:', header);

  // Parse data rows
  const rows: RawDataRow[] = [];

  for (let i = 1; i < lines.length; i++) {
    const line = lines[i].trim();
    if (!line) continue;

    // Split by spaces but preserve quoted strings
    const values = parseRDataLine(line);

    if (values.length >= header.length) {
      const row: any = {};
      header.forEach((col, index) => {
        row[col] = values[index] || '';
      });

      rows.push({
        player: row.player || '',
        category: row.category || '',
        score: row.score || '',
        model: row.model || '',
        code: row.code || '',
        brand: row.brand || '',
        flex: row.flex || '',
        swingweight: row.swingweight || '',
        length: row.length || '',
        head_size: row.head_size || '',
        weight: row.weight || '',
        balance: row.balance || '',
        construction: row.construction || '',
        material: row.material || '',
        string_pattern: row.string_pattern || '',
      });
    }
  }

  return rows;
}

function parseRDataLine(line: string): string[] {
  const values: string[] = [];
  let current = '';
  let inQuotes = false;
  let i = 0;

  while (i < line.length) {
    const char = line[i];

    if (char === '"') {
      inQuotes = !inQuotes;
    } else if (char === ' ' && !inQuotes) {
      if (current.trim()) {
        values.push(current.trim());
        current = '';
      }
    } else {
      current += char;
    }

    i++;
  }

  if (current.trim()) {
    values.push(current.trim());
  }

  return values.map(val => val.replace(/^"|"$/g, ''));
}

