    const racquetsWithAverages = processor.computePerformanceAverages(racquets, reviews);

    console.log('Extracting brands...');
    const brands = processor.extractBrands(racquetsWithAverages);
    console.log(`Found ${brands.length} brands`);

    // Write output files
    console.log('Writing output files...');

    fs.writeFileSync(
      path.join(outputDir, 'racquets.json'),
      JSON.stringify(racquetsWithAverages, null, 2)
    );

    fs.writeFileSync(
      path.join(outputDir, 'reviews.json'),
      JSON.stringify(reviews, null, 2)
    );

    fs.writeFileSync(
      path.join(outputDir, 'brands.json'),
      JSON.stringify(brands, null, 2)
    );

    // Generate summary statistics
    const stats = {
      total_racquets: racquetsWithAverages.length,
      total_reviews: reviews.length,
      total_brands: brands.length,
      avg_reviews_per_racquet: Math.round(reviews.length / racquetsWithAverages.length * 10) / 10,
      brands: brands.map(b => ({ name: b.name, count: b.racquet_count })),
      generated_at: new Date().toISOString(),
    };

    fs.writeFileSync(
      path.join(outputDir, 'stats.json'),
      JSON.stringify(stats, null, 2)
    );

    console.log('Data processing complete!');
    console.log(`- ${stats.total_racquets} racquets`);
    console.log(`- ${stats.total_reviews} reviews`);
    console.log(`- ${stats.total_brands} brands`);
    console.log(`- ${stats.avg_reviews_per_racquet} avg reviews per racquet`);

  } catch (error) {
    console.error('Error processing data:', error);
    process.exit(1);
  }
}

if (require.main === module) {
  main();
}

