// Data processing utilities for converting R data to structured format

import { Racquet, Review, PERFORMANCE_CATEGORIES } from './types';

interface RawDataRow {
  player: string;
  category: string;
  score: string;
  model: string;
  code: string;
  brand: string;
  flex: string;
  swingweight: string;
  length: string;
  head_size: string;
  weight: string;
  balance: string;
  construction: string;
  material: string;
  string_pattern: string;
}

export class DataProcessor {
  private rawData: RawDataRow[] = [];

  constructor(rawData: RawDataRow[]) {
    this.rawData = rawData;
  }

  /**
   * Parse numeric values from string specifications
   */
  private parseSpecs(row: RawDataRow) {
    // Parse weight (e.g., "11.2oz oz" -> 11.2)
    const weight_oz = this.parseFloat(row.weight?.replace(/[^\d.]/g, ''));

    // Parse length (e.g., "27 in" -> 27)
    const length_in = this.parseFloat(row.length?.replace(/[^\d.]/g, ''));

    // Parse head size (e.g., "100 sq in" -> 100)
    const head_size_sq_in = this.parseFloat(row.head_size?.replace(/[^\d.]/g, ''));

    // Parse balance (e.g., "12.99in / 32.99cm / 4 pts HL" -> 12.99, 4)
    const balance_match = row.balance?.match(/(\d+\.?\d*)/g);
    const balance_in = balance_match ? parseFloat(balance_match[0]) : undefined;

    // Calculate balance points (head light/heavy)
    let balance_pts = 0;
    if (balance_in && length_in) {
      const midpoint = length_in / 2;
      const diff = midpoint - balance_in;
      balance_pts = Math.round(diff * 8); // Convert to points (1/8 inch)
    }

    return {
      weight_oz,
      length_in,
      head_size_sq_in,
      balance_in,
      balance_pts,
      flex: this.parseFloat(row.flex),
      swingweight: this.parseFloat(row.swingweight),
    };
  }

  private parseFloat(value: string | number): number | undefined {
    if (typeof value === 'number') return value;
    if (!value || value === '') return undefined;
    const parsed = parseFloat(String(value));
    return isNaN(parsed) ? undefined : parsed;
  }

  /**
   * Extract unique racquets from the raw data
   */
  public extractRacquets(): Racquet[] {
    const racquetMap = new Map<string, Racquet>();

    for (const row of this.rawData) {
      if (!row.code || !row.model) continue;

      if (!racquetMap.has(row.code)) {
        const specs = this.parseSpecs(row);

        const racquet: Racquet = {
          id: row.code,
          code: row.code,
          model: row.model.trim(),
          brand: row.brand.trim(),
          flex: specs.flex || 0,
          swingweight: specs.swingweight || 0,
          length: row.length?.trim() || '',
          head_size: row.head_size?.trim() || '',
          weight: row.weight?.trim() || '',
          balance: row.balance?.trim() || '',
          construction: row.construction?.trim() || '',
          material: row.material?.trim() || '',
          string_pattern: row.string_pattern?.trim() || '',

          // Computed values
          weight_oz: specs.weight_oz,
          length_in: specs.length_in,
          head_size_sq_in: specs.head_size_sq_in,
          balance_in: specs.balance_in,
          balance_pts: specs.balance_pts,

          created_at: new Date().toISOString(),
          updated_at: new Date().toISOString(),
        };

        racquetMap.set(row.code, racquet);
      }
    }

    return Array.from(racquetMap.values());
  }

  /**
   * Extract all reviews from the raw data
   */
  public extractReviews(): Review[] {
    const reviews: Review[] = [];
    let reviewId = 1;

    for (const row of this.rawData) {
      // Skip empty rows or rows without proper data
      if (!row.code || !row.player || !row.category || !row.score) {
        continue;
      }

      // Skip empty categories
      if (row.category.trim() === '') continue;

      const score = this.parseFloat(row.score);
      if (score === undefined) continue;

      // Normalize score to 0-10 scale
      const normalizedScore = score > 10 ? score / 10 : score;

      const review: Review = {
        id: `review_${reviewId++}`,
        racquet_id: row.code,
        player_name: this.cleanPlayerName(row.player),
        category: this.normalizeCategory(row.category),
        score: normalizedScore,
        created_at: new Date().toISOString(),
      };

      reviews.push(review);
    }

    return reviews;
  }

  /**
   * Clean player names (remove apostrophes, etc.)
   */
  private cleanPlayerName(name: string): string {
    return name
      .replace(/['']s?$/, '') // Remove trailing 's or '
      .replace(/^['']/, '') // Remove leading '
      .trim();
  }

  /**
   * Normalize category names to match our standard list
   */
  private normalizeCategory(category: string): string {
    const cleaned = category.trim();

    // Handle special cases
    const mappings: Record<string, string> = {
      'Touch/Feel': 'Touch/Feel',
      'Touch / Feel': 'Touch/Feel',
      'TouchFeel': 'Touch/Feel',
    };

    return mappings[cleaned] || cleaned;
  }

  /**
   * Compute average performance scores for each racquet
   */
  public computePerformanceAverages(racquets: Racquet[], reviews: Review[]): Racquet[] {
    const reviewsByRacquet = this.groupReviewsByRacquet(reviews);

    return racquets.map(racquet => {
      const racquetReviews = reviewsByRacquet.get(racquet.id) || [];
      const averages = this.calculateCategoryAverages(racquetReviews);

      return {
        ...racquet,
        ...averages,
        review_count: racquetReviews.length,
      };
    });
  }

  private groupReviewsByRacquet(reviews: Review[]): Map<string, Review[]> {
    const grouped = new Map<string, Review[]>();

    for (const review of reviews) {
      if (!grouped.has(review.racquet_id)) {
        grouped.set(review.racquet_id, []);
      }
      grouped.get(review.racquet_id)!.push(review);
    }

    return grouped;
  }

  private calculateCategoryAverages(reviews: Review[]): Partial<Racquet> {
    const categoryScores = new Map<string, number[]>();

    // Group scores by category
    for (const review of reviews) {
      if (!categoryScores.has(review.category)) {
        categoryScores.set(review.category, []);
      }
      categoryScores.get(review.category)!.push(review.score);
    }

    // Calculate averages
    const averages: Partial<Racquet> = {};

    for (const [category, scores] of categoryScores) {
      const avg = scores.reduce((sum, score) => sum + score, 0) / scores.length;
      const roundedAvg = Math.round(avg * 10) / 10; // Round to 1 decimal

      switch (category) {
        case 'Power': averages.power_avg = roundedAvg; break;
        case 'Control': averages.control_avg = roundedAvg; break;
        case 'Comfort': averages.comfort_avg = roundedAvg; break;
        case 'Maneuverability': averages.maneuverability_avg = roundedAvg; break;
        case 'Stability': averages.stability_avg = roundedAvg; break;
        case 'Serves': averages.serves_avg = roundedAvg; break;
        case 'Returns': averages.returns_avg = roundedAvg; break;
        case 'Groundstrokes': averages.groundstrokes_avg = roundedAvg; break;
        case 'Volleys': averages.volleys_avg = roundedAvg; break;
        case 'Slice': averages.slice_avg = roundedAvg; break;
        case 'Topspin': averages.topspin_avg = roundedAvg; break;
        case 'Touch/Feel': averages.touch_feel_avg = roundedAvg; break;
        case 'Overall': averages.overall_avg = roundedAvg; break;
      }
    }

    return averages;
  }

  /**
   * Get unique brands from the data
   */
  public extractBrands(racquets: Racquet[]) {
    const brandMap = new Map<string, { name: string; count: number }>();

    for (const racquet of racquets) {
      const brand = racquet.brand;
      if (brandMap.has(brand)) {
        brandMap.get(brand)!.count++;
      } else {
        brandMap.set(brand, { name: brand, count: 1 });
      }
    }

    return Array.from(brandMap.entries()).map(([id, data]) => ({
      id: id.toLowerCase().replace(/\s+/g, '-'),
      name: data.name,
      racquet_count: data.count,
    }));
  }
}

