import { NextRequest, NextResponse } from 'next/server';
import { ApiResponse, Racquet, RacquetFilters } from '@/lib/types';
import { RacquetService } from '@/lib/services/racquet-service';

export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url);

    // Parse query parameters
    const filters: RacquetFilters = {
      brand: searchParams.get('brand')?.split(',') || undefined,
      weight_min: searchParams.get('weight_min') ? Number(searchParams.get('weight_min')) : undefined,
      weight_max: searchParams.get('weight_max') ? Number(searchParams.get('weight_max')) : undefined,
      head_size_min: searchParams.get('head_size_min') ? Number(searchParams.get('head_size_min')) : undefined,
      head_size_max: searchParams.get('head_size_max') ? Number(searchParams.get('head_size_max')) : undefined,
      power_min: searchParams.get('power_min') ? Number(searchParams.get('power_min')) : undefined,
      power_max: searchParams.get('power_max') ? Number(searchParams.get('power_max')) : undefined,
      control_min: searchParams.get('control_min') ? Number(searchParams.get('control_min')) : undefined,
      control_max: searchParams.get('control_max') ? Number(searchParams.get('control_max')) : undefined,
      search: searchParams.get('search') || undefined,
      limit: searchParams.get('limit') ? Number(searchParams.get('limit')) : 50,
      offset: searchParams.get('offset') ? Number(searchParams.get('offset')) : 0,
    };

    const racquetService = new RacquetService();
    const { racquets, total } = await racquetService.getRacquets(filters);

    const response: ApiResponse<Racquet[]> = {
      data: racquets,
      meta: {
        total,
        page: Math.floor(filters.offset! / filters.limit!) + 1,
        limit: filters.limit!,
      },
    };

    return NextResponse.json(response);
  } catch (error) {
    console.error('Error fetching racquets:', error);
    return NextResponse.json(
      { error: 'Failed to fetch racquets' },
      { status: 500 }
    );
  }
}

