import fs from 'fs';
import path from 'path';
import { Racquet, Review, RacquetWithReviews, RacquetFilters } from '@/lib/types';

export class RacquetService {
  private racquets: Racquet[] = [];
  private reviews: Review[] = [];
  private initialized = false;

  private async initialize() {
    if (this.initialized) return;

    const dataDir = path.join(process.cwd(), 'src/data');

    // Load racquets
    const racquetsData = fs.readFileSync(path.join(dataDir, 'racquets.json'), 'utf-8');
    this.racquets = JSON.parse(racquetsData);

    // Load reviews
    const reviewsData = fs.readFileSync(path.join(dataDir, 'reviews.json'), 'utf-8');
    this.reviews = JSON.parse(reviewsData);

    this.initialized = true;
  }

  async getRacquets(filters: RacquetFilters = {}) {
    await this.initialize();

    let filtered = [...this.racquets];

    // Apply filters
    if (filters.brand && filters.brand.length > 0) {
      filtered = filtered.filter(r => filters.brand!.includes(r.brand));
    }

    if (filters.weight_min !== undefined) {
      filtered = filtered.filter(r => r.weight_oz && r.weight_oz >= filters.weight_min!);
    }

    if (filters.weight_max !== undefined) {
      filtered = filtered.filter(r => r.weight_oz && r.weight_oz <= filters.weight_max!);
    }

    if (filters.head_size_min !== undefined) {
      filtered = filtered.filter(r => r.head_size_sq_in && r.head_size_sq_in >= filters.head_size_min!);
    }

    if (filters.head_size_max !== undefined) {
      filtered = filtered.filter(r => r.head_size_sq_in && r.head_size_sq_in <= filters.head_size_max!);
    }

    if (filters.power_min !== undefined) {
      filtered = filtered.filter(r => r.power_avg && r.power_avg >= filters.power_min!);
    }

    if (filters.power_max !== undefined) {
      filtered = filtered.filter(r => r.power_avg && r.power_avg <= filters.power_max!);
    }

    if (filters.control_min !== undefined) {
      filtered = filtered.filter(r => r.control_avg && r.control_avg >= filters.control_min!);
    }

    if (filters.control_max !== undefined) {
      filtered = filtered.filter(r => r.control_avg && r.control_avg <= filters.control_max!);
    }

    if (filters.search) {
      const searchLower = filters.search.toLowerCase();
      filtered = filtered.filter(r => 
        r.model.toLowerCase().includes(searchLower) ||
        r.brand.toLowerCase().includes(searchLower)
      );
    }

    const total = filtered.length;

    // Apply pagination
    const limit = filters.limit || 50;
    const offset = filters.offset || 0;
    const paginated = filtered.slice(offset, offset + limit);

    return {
      racquets: paginated,
      total,
    };
  }

  async getRacquetById(id: string): Promise<RacquetWithReviews | null> {
    await this.initialize();

    const racquet = this.racquets.find(r => r.id === id);
    if (!racquet) return null;

    const racquetReviews = this.reviews.filter(r => r.racquet_id === id);

    return {
      ...racquet,
      reviews: racquetReviews,
    };
  }

  async getRacquetsByBrand(brand: string): Promise<Racquet[]> {
    await this.initialize();
    return this.racquets.filter(r => r.brand === brand);
  }

  async searchRacquets(query: string): Promise<Racquet[]> {
    await this.initialize();

    const searchLower = query.toLowerCase();
    return this.racquets.filter(r => 
      r.model.toLowerCase().includes(searchLower) ||
      r.brand.toLowerCase().includes(searchLower)
    );
  }
}

