import { Brand } from '@/lib/types';

export class BrandService {
  private brands: Brand[] = [];
  private initialized = false;

  private async initialize() {
    if (this.initialized) return;

    const dataDir = path.join(process.cwd(), 'src/data');
    const brandsData = fs.readFileSync(path.join(dataDir, 'brands.json'), 'utf-8');
    this.brands = JSON.parse(brandsData);

    this.initialized = true;
  }

  async getBrands(): Promise<Brand[]> {
    await this.initialize();
    return this.brands.sort((a, b) => a.name.localeCompare(b.name));
  }

  async getBrandById(id: string): Promise<Brand | null> {
    await this.initialize();
    return this.brands.find(b => b.id === id) || null;
  }

  async getBrandByName(name: string): Promise<Brand | null> {
    await this.initialize();
    return this.brands.find(b => b.name === name) || null;
  }
}

